import java.io.*;
import org.owasp.encoder.Encode;

public class SecureXSSExample {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            // Properly handle user input by escaping it before outputting to the web page
            String sanitizedInput = Encode.forHtml(userInput);
            System.out.println("<p>Welcome, " + sanitizedInput + "!</p>");
        } catch (IOException e) {
            System.err.println("Error reading input");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
